   217→    // setting the buffer to stale, all we care about for a pure sender is wether
   218→    // or not its last send message has been completed
   219→    if (*state_ == BufferState::stale) return true;
   220→    if (*my_request_ == MPI_REQUEST_NULL) return true;
   221→    int flag, test;
   222→    PARTHENON_MPI_CHECK(MPI_Iprobe(MPI_ANY_SOURCE, MPI_ANY_TAG, MPI_COMM_WORLD, &test,
   223→                                   MPI_STATUS_IGNORE));
   224→    PARTHENON_MPI_CHECK(MPI_Test(my_request_.get(), &flag, MPI_STATUS_IGNORE));
   225→    if (flag) *state_ = BufferState::stale;
   226→    return flag;
   227→#else
   228→    PARTHENON_FAIL("Should not have a sending buffer when MPI is not enabled.");
   229→#endif
   230→  } else if (*comm_type_ == BuffCommType::both) {
   231→    return (*state_ == BufferState::stale);
