   237→template <class T>
   238→void CommBuffer<T>::TryStartReceive() noexcept {
   239→#ifdef MPI_PARALLEL
   240→  if (*comm_type_ == BuffCommType::receiver && !*started_irecv_) {
   241→    PARTHENON_REQUIRE(
   242→        *my_request_ == MPI_REQUEST_NULL,
   243→        "Cannot have another pending request in a buffer that is starting to receive.");
   244→    if (!IsActive())
   245→      Allocate(); // For early start of Irecv, always need storage space even if not used
   246→    PARTHENON_MPI_CHECK(MPI_Irecv(buf_.data(), buf_.size(),
   247→                                  MPITypeMap<buf_base_t>::type(), send_rank_, tag_, comm_,
   248→                                  my_request_.get()));
   249→    *started_irecv_ = true;
   250→  } else if (*comm_type_ == BuffCommType::sparse_receiver && !*started_irecv_) {
   251→    int test;
   252→    MPI_Status status;
   253→    // Check if our message is available so that we can use the correct buffer size
   254→    PARTHENON_MPI_CHECK(MPI_Iprobe(send_rank_, tag_, comm_, &test, &status));
   255→    if (test) {
   256→      // For optimal buffer memory useage, we can only post the Irecv once we know the
   257→      // size of the incoming buffer
   258→      int size;
   259→      PARTHENON_MPI_CHECK(MPI_Get_count(&status, MPITypeMap<buf_base_t>::type(), &size));
   260→      if (size > 0) {
   261→        if (!active_) Allocate();
   262→        PARTHENON_MPI_CHECK(MPI_Irecv(buf_.data(), buf_.size(),
   263→                                      MPITypeMap<buf_base_t>::type(), send_rank_, tag_,
   264→                                      comm_, my_request_.get()));
   265→      } else {
   266→        if (active_) Free();
   267→        PARTHENON_MPI_CHECK(MPI_Irecv(&null_buf_, 0, MPITypeMap<buf_base_t>::type(),
   268→                                      send_rank_, tag_, comm_, my_request_.get()));
   269→      }
   270→      *started_irecv_ = true;
   271→    }
   272→  }
   273→#endif
   274→}
