   276→template <class T>
   277→bool CommBuffer<T>::TryReceive() noexcept {
   278→  if (*state_ == BufferState::received || *state_ == BufferState::received_null)
   279→    return true;
   280→
   281→  if (*comm_type_ == BuffCommType::receiver ||
   282→      *comm_type_ == BuffCommType::sparse_receiver) {
   283→#ifdef MPI_PARALLEL
   284→    (*nrecv_tries_)++;
   285→    PARTHENON_REQUIRE(*nrecv_tries_ < 1e8,
   286→                      "MPI probably hanging after 1e8 receive tries.");
   287→
   288→    TryStartReceive();
   289→
   290→    if (*started_irecv_) {
   291→      MPI_Status status;
   292→      int flag;
   293→      // Comment from original Athena++ code about the MPI_Iprobe call:
   294→      //
   295→      // Although MPI_Iprobe does nothing for us (it checks arrival of any message but
   296→      // we do not use the result), this is ABSOLUTELY NECESSARY for the performance of
   297→      // Athena++. Although non-blocking MPI communications look like multi-tasking
   298→      // running behind our code, actually they are not. The network interface card can
   299→      // run autonomously from the CPU, but to move the data between the memory and the
   300→      // network interface and initiate/complete communications, MPI has to do something
   301→      // using CPU. So to process communications, we have to allow MPI to use CPU.
   302→      // Theoretically MPI can use multi-thread for this (OpenMPI can be configured so)
   303→      // but it is not common because of performance and compatibility issues. Instead,
   304→      // MPI processes communications whenever any MPI function is called. MPI_Iprobe is
   305→      // one of the cheapest function in MPI and by calling this occasionally MPI can
   306→      // process communications "as if it is in the background". Using only MPI_Test,
   307→      // the communications were very slow. I suspect that MPI_Test changes the ordering
   308→      // of the messages internally (I guess it tries to promote the message it is
   309→      // Testing), and if we call MPI_Test for different messages, they are left half
   310→      // done. So if we remove them, I am sure we will see significant performance drop.
   311→      // I could not dig it up right now, Collela or Woodward mentioned this in a paper.
   312→      //
   313→      // Depending on the MPI implementation and the order of MPI_Test calls, as well
   314→      // as the total number of buffers being communicated, I have found this can have
   315→      // anywhere from no impact on the walltime to a factor of a few reduction in the
   316→      // walltime. It seems to be unpredictable as far as I can tell.
   317→      for (int i = 0; i < 1; ++i)
   318→        PARTHENON_MPI_CHECK(MPI_Iprobe(MPI_ANY_SOURCE, MPI_ANY_TAG, MPI_COMM_WORLD, &flag,
   319→                                       MPI_STATUS_IGNORE));
   320→      PARTHENON_MPI_CHECK(MPI_Test(my_request_.get(), &flag, &status));
   321→
   322→      if (flag != 0 and flag != 1) {
   323→        std::cout << "Weird value of flag: " << flag << std::endl;
   324→      }
   325→      if (flag) {
   326→        // Check the size of the message, it will be zero if the sender wants you to use
   327→        // default buffer data
   328→        int size;
   329→        PARTHENON_MPI_CHECK(
   330→            MPI_Get_count(&status, MPITypeMap<buf_base_t>::type(), &size));
   331→
   332→        PARTHENON_REQUIRE(*my_request_ == MPI_REQUEST_NULL,
   333→                          "MPI request should be finished to get here.");
   334→        // Set flags based on a finished receive
   335→        *started_irecv_ = false;
   336→        *nrecv_tries_ = 0;
   337→        if (size > 0)
   338→          *state_ = BufferState::received;
   339→        else
   340→          *state_ = BufferState::received_null;
   341→
   342→        return true;
   343→      }
   344→    }
   345→    return false;
   346→#else
   347→    PARTHENON_FAIL("Should not have a purely receiving buffer without MPI enabled.");
   348→#endif
   349→  } else if (*comm_type_ == BuffCommType::both) {
   350→    if (*state_ == BufferState::sending) {
   351→      *state_ = BufferState::received;
   352→      // Memory should already be available, since both
   353→      // send and receive rank point at the same memory
   354→      return true;
   355→    } else if (*state_ == BufferState::sending_null) {
   356→      *state_ = BufferState::received_null;
   357→      return true;
   358→    }
   359→    return false;
   360→  } else {
   361→    // This is an error since this is a purely send buffer
   362→    PARTHENON_FAIL("Trying to receive on a sender");
   363→  }
   364→  return false;
   365→}
   366→
   367→template <class T>
   368→void CommBuffer<T>::Stale() {
   369→  PARTHENON_REQUIRE(*comm_type_ != BuffCommType::sender, "Should never get here.");
   370→
   371→  if (!(*state_ == BufferState::received || *state_ == BufferState::received_null))
   372→    PARTHENON_DEBUG_WARN("Staling buffer not in the received state.");
   373→#ifdef MPI_PARALLEL
   374→  if (MPI_REQUEST_NULL != *my_request_)
   375→    PARTHENON_WARN("Staling buffer with pending request.");
   376→#endif
   377→  *state_ = BufferState::stale;
   378→}
   379→
   380→template <class T>
   381→void CommBuffer<T>::SendGap() {
   382→  static uint64_t sleep_ns = 0;
   383→  if (sleep_ns == 0) {
   384→    const char *env = std::getenv("PARTHENON_SEND_GAP_NS");
   385→    if (env) {
   386→      sleep_ns = std::stoul(env);
   387→    } else {
   388→      sleep_ns = 1;
   389→    }
   390→  }
   391→
   392→  static struct timespec ts;
   393→  ts.tv_sec = 0;
   394→  ts.tv_nsec = sleep_ns;
   395→  nanosleep(&ts, nullptr);
   396→}
   397→
   398→template class CommBuffer<parthenon::ObjectPool<Kokkos::View<double*, Kokkos::LayoutRight, Kokkos::HostSpace>>::owner_t>;
   399→} // namespace parthenon
